sys_script_include.script:
var ChromaTechQueryUtils = Class.create();
ChromaTechQueryUtils.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    copyQuery: function () {
        var sourceSysId = this.getParameter('sysparm_source_sys_id');

        if (!sourceSysId)
            return '';

        var sourceGR = new GlideRecord('x_1839224_chroma_0_chromatech_customer_queries');
        if (!sourceGR.get(sourceSysId))
            return '';

        var targetGR = new GlideRecord('x_1839224_chroma_0_chromatech_customer_queries');
        targetGR.initialize();

        // Copy fields (BEST PRACTICE: whitelist)
        var fieldsToCopy = [
            'short_description',
            'description',
            'category',
            'priority',
            'requester',
			'product'
            // add more fields here as needed
        ];

        for (var i = 0; i < fieldsToCopy.length; i++) {
            targetGR.setValue(
                fieldsToCopy[i],
                sourceGR.getValue(fieldsToCopy[i])
            );
        }

        // Optional: reset state
        // targetGR.setValue('state', 'new');

        var newSysId = targetGR.insert();

        return newSysId;
    },

    type: 'ChromaTechQueryUtils'
});
